/* ─────────────────────────────────────────────
   BRAND LOGO (base64 — green-filtered at render)
───────────────────────────────────────────── */
const LOGO_B64 = "data:image/jpeg;base64,";
const CULTIVATION_IMG = "data:image/jpeg;base64,";
const DISPENSARY_IMG   = "data:image/jpeg;base64,";


const LogoImg = ({ size = 32, dark = false, style = {} }) => {
  const [src, setSrc] = useState(LOGO_B64);
  useEffect(() => {
    const img = new Image();
    img.onload = () => {
      const c = document.createElement("canvas");
      c.width = img.width; c.height = img.height;
      const ctx = c.getContext("2d");
      ctx.drawImage(img, 0, 0);
      const id = ctx.getImageData(0, 0, c.width, c.height);
      const d = id.data;
      for (let i = 0; i < d.length; i += 4) {
        if (d[i] < 40 && d[i+1] < 40 && d[i+2] < 40) d[i+3] = 0;
      }
      ctx.putImageData(id, 0, 0);
      setSrc(c.toDataURL("image/png"));
    };
    img.src = LOGO_B64;
  }, []);
  return (
    <img src={src} width={size} height={size} alt="CompliancePilot" style={{
      objectFit:"contain", display:"block", ...style,
    }}/>
  );
};

