const StatCard = ({ label, value, sub, icon: Icon, color, trend, small }) => (
  <div style={{ background:"#ffffff", border:"1px solid #e2e8f0", borderRadius:12, boxShadow:"0 1px 4px rgba(0,0,0,0.04)", padding: small ? "14px 16px" : "18px 20px", flex:1, minWidth:120 }}>
    <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:10 }}>
      <div style={{ fontSize:10, textTransform:"uppercase", letterSpacing:"0.8px", fontWeight:600, color:T.text3 }}>{label}</div>
      {Icon && <div style={{ width:26, height:26, borderRadius:7, background:`${color || T.green}18`, display:"flex", alignItems:"center", justifyContent:"center" }}><Icon size={13} color={color || T.green}/></div>}
    </div>
    <div style={{ fontSize: small ? 22 : 28, fontWeight:700, fontFamily:"'IBM Plex Mono',monospace", color: color || T.text1, lineHeight:1 }}>{value}</div>
    {sub && <div style={{ fontSize:11, color:T.text3, marginTop:5 }}>{sub}</div>}
    {trend !== undefined && (
      <div style={{ display:"flex", alignItems:"center", gap:4, marginTop:6 }}>
        <ArrowUpRight size={11} color={trend > 0 ? T.red : T.green}/>
        <span style={{ fontSize:11, color: trend > 0 ? T.red : T.green }}>{Math.abs(trend)} this week</span>
      </div>
    )}
  </div>
);

const customTooltipStyle = { background:T.card, border:`1px solid ${T.borderLight}`, borderRadius:8, padding:"8px 12px" };

const ChartTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={customTooltipStyle}>
      <p style={{ color:T.text2, fontSize:11, marginBottom:4 }}>{label}</p>
      {payload.map((p, i) => (
        <p key={i} style={{ color:p.color, fontSize:13, fontWeight:700, fontFamily:"'IBM Plex Mono',monospace" }}>
          {p.name}: {p.value}
        </p>
      ))}
    </div>
  );
};

