const TourOverlay = ({ step, total, onNext, onPrev, onSkip, targetRect, font }) => {
  const f = font || "'Plus Jakarta Sans',sans-serif";
  const s = TOUR_STEPS[step];
  const isCenter = s.position === "center";
  const isFirst  = step === 0;
  const isLast   = step === TOUR_STEPS.length - 1;

  let tooltipStyle = {
    position:"fixed", zIndex:99998,
    background:"#0b1f3a",
    border:"1px solid rgba(255,255,255,0.12)",
    borderRadius:16,
    padding:"22px 24px 20px",
    width:340,
    boxShadow:"0 20px 60px rgba(0,0,0,0.45), 0 4px 16px rgba(0,0,0,0.3)",
    fontFamily:f,
    animation:"revealScaleUp 0.25s cubic-bezier(.22,1,.36,1) both",
  };

  if (isCenter) {
    tooltipStyle = { ...tooltipStyle, top:"50%", left:"50%", transform:"translate(-50%,-50%)" };
  } else if (targetRect) {
    const pad = 16;
    if (s.position === "bottom") {
      tooltipStyle.top  = targetRect.bottom + pad;
      tooltipStyle.left = Math.max(16, Math.min(targetRect.left, window.innerWidth - 356));
    } else if (s.position === "top") {
      tooltipStyle.bottom = window.innerHeight - targetRect.top + pad;
      tooltipStyle.left   = Math.max(16, Math.min(targetRect.left, window.innerWidth - 356));
    } else if (s.position === "left") {
      tooltipStyle.top   = Math.max(16, targetRect.top);
      tooltipStyle.right = window.innerWidth - targetRect.left + pad;
      tooltipStyle.left  = "auto";
    }
  } else {
    tooltipStyle = { ...tooltipStyle, top:"50%", left:"50%", transform:"translate(-50%,-50%)" };
  }

  return (
    <>
      {/* Backdrop — no blur, no pointer blocking so user can scroll */}
      <div style={{ position:"fixed", inset:0, zIndex:99997, background:"rgba(5,15,8,0.45)", pointerEvents:"none" }}/>

      {/* Spotlight on target */}
      {targetRect && !isCenter && (
        <div style={{
          position:"fixed", zIndex:99997,
          top:    targetRect.top    - 6,
          left:   targetRect.left   - 6,
          width:  targetRect.width  + 12,
          height: targetRect.height + 12,
          borderRadius:12,
          border:"2px solid rgba(34,197,94,0.9)",
          boxShadow:"0 0 0 9999px rgba(5,15,8,0.45), 0 0 28px rgba(34,197,94,0.35)",
          pointerEvents:"none",
          animation:"swPulse 2s ease-in-out infinite",
        }}/>
      )}

      {/* Tooltip */}
      <div style={tooltipStyle}>
        {/* Step counter */}
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
          <div style={{ display:"flex", gap:5 }}>
            {TOUR_STEPS.map((_,i) => (
              <div key={i} style={{ width: i===step ? 18 : 6, height:6, borderRadius:3, background: i===step ? "#22c55e" : i<step ? "rgba(34,197,94,0.4)" : "rgba(255,255,255,0.15)", transition:"all 0.3s ease" }}/>
            ))}
          </div>
          <button onClick={onSkip} style={{ background:"none", border:"none", cursor:"pointer", color:"rgba(255,255,255,0.35)", fontSize:12, fontFamily:f, padding:"2px 6px" }}>
            Skip tour
          </button>
        </div>

        {/* Content */}
        <div style={{ fontSize:16, fontWeight:700, color:"#fff", marginBottom:8, letterSpacing:"-0.3px", lineHeight:1.3 }}>
          {s.title}
        </div>
        <div style={{ fontSize:13.5, color:"rgba(255,255,255,0.62)", lineHeight:1.7, marginBottom:20 }}>
          {s.body}
        </div>

        {/* Actions */}
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <div style={{ fontSize:11, color:"rgba(255,255,255,0.28)", fontFamily:"'Space Mono',monospace" }}>
            {step+1} / {total}
          </div>
          <div style={{ display:"flex", gap:8 }}>
            {!isFirst && (
              <button onClick={onPrev} style={{ background:"rgba(255,255,255,0.08)", border:"1px solid rgba(255,255,255,0.14)", borderRadius:8, padding:"8px 16px", color:"rgba(255,255,255,0.65)", fontSize:13, fontWeight:600, cursor:"pointer", fontFamily:f, transition:"all 0.15s" }}
                onMouseEnter={e=>e.currentTarget.style.background="rgba(255,255,255,0.14)"}
                onMouseLeave={e=>e.currentTarget.style.background="rgba(255,255,255,0.08)"}>
                ← Back
              </button>
            )}
            <button onClick={isLast ? onSkip : onNext} style={{ background:"linear-gradient(135deg,#16a34a,#22c55e)", border:"none", borderRadius:8, padding:"8px 18px", color:"#fff", fontSize:13, fontWeight:700, cursor:"pointer", fontFamily:f, transition:"all 0.18s" }}
              onMouseEnter={e=>{e.currentTarget.style.background="linear-gradient(135deg,#15803d,#16a34a)";e.currentTarget.style.transform="translateY(-1px)";}}
              onMouseLeave={e=>{e.currentTarget.style.background="linear-gradient(135deg,#16a34a,#22c55e)";e.currentTarget.style.transform="none";}}>
              {isLast ? "Done 🎉" : "Next →"}
            </button>
          </div>
        </div>
      </div>
    </>
  );
};

const DashboardPage = ({ setPage, currentUser }) => {
  const { dark, theme:th } = useTheme();
  const D = th || LIGHT;
  const font = "'Plus Jakarta Sans',sans-serif";
  const mono = "'Space Mono',monospace";

  const highRisk  = LOCATIONS.filter(l => l.status === "high").length;
  const openTasks = TASKS_INIT.filter(t => t.status !== "completed").length;
  const overdue   = TASKS_INIT.filter(t => t.status === "overdue").length;
  const completed = TASKS_INIT.filter(t => t.status === "completed").length;
  const pct       = Math.round((completed/TASKS_INIT.length)*100);
  const hour      = new Date().getHours();
  const greeting  = hour<12?"Good morning":hour<17?"Good afternoon":"Good evening";
  const firstName = currentUser?.name?.split(" ")[0] || "there";

  // Mini sparkline for KPI cards
  const Spark = ({ data, color, width=64, height=28 }) => {
    const max = Math.max(...data), min = Math.min(...data);
    const range = max - min || 1;
    const pts = data.map((v,i) => `${(i/(data.length-1))*width},${height-((v-min)/range)*height}`).join(" ");
    return (
      <svg width={width} height={height} style={{display:"block"}}>
        <polyline points={pts} fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" opacity="0.8"/>
      </svg>
    );
  };

  const cs = {
    background:D.card, border:`1px solid ${D.border}`,
    borderRadius:12, transition:"background 0.3s",
    boxShadow: dark?"0 1px 8px rgba(0,0,0,0.3)":"0 1px 4px rgba(0,0,0,0.04)",
  };

  const CT = ({ active, payload, label }) => {
    if (!active || !payload?.length) return null;
    return (
      <div style={{background:D.card,border:`1px solid ${D.border}`,borderRadius:8,padding:"8px 12px",fontSize:12,fontFamily:font,boxShadow:"0 4px 16px rgba(0,0,0,0.12)"}}>
        <div style={{color:D.text3,marginBottom:4}}>{label}</div>
        {payload.map((p,i)=><div key={i} style={{color:p.color,fontWeight:700}}>{p.name}: {p.value}</div>)}
      </div>
    );
  };

  return (
    <div style={{background:D.bg, minHeight:"100vh", transition:"background 0.3s", fontFamily:font}}>
      <TopBar title="Dashboard" sub={`${currentUser?.roleLabel || "Executive"} · Jushi Holdings Inc.`}/>
      <div style={{padding:"28px 32px 48px"}}>

        {/* ── WELCOME BANNER ── */}
        <div style={{
          background: dark?"linear-gradient(135deg,#0d2137,#0a2010)":"linear-gradient(135deg,#0b1f3a,#16a34a)",
          borderRadius:16, padding:"28px 32px", marginBottom:28,
          display:"flex", alignItems:"center", justifyContent:"space-between",
          position:"relative", overflow:"hidden",
        }}>
          <div style={{position:"absolute",right:-40,top:-40,width:200,height:200,borderRadius:"50%",background:"rgba(255,255,255,0.03)",pointerEvents:"none"}}/>
          <div>
            <div style={{fontSize:12,color:"rgba(255,255,255,0.4)",letterSpacing:"1px",marginBottom:6,fontFamily:mono}}>
              {new Date().toLocaleDateString("en-US",{weekday:"long",month:"long",day:"numeric",year:"numeric"})}
            </div>
            <div style={{fontSize:22,fontWeight:800,color:"#fff",letterSpacing:"-0.5px",marginBottom:6}}>
              {greeting}, {firstName} 👋
            </div>
            <div style={{fontSize:14,color:"rgba(255,255,255,0.55)"}}>
              You have <span style={{color:"#f87171",fontWeight:700}}>{overdue} overdue tasks</span> and <span style={{color:"#fbbf24",fontWeight:700}}>{openTasks} open items</span> across 6 states.
            </div>
          </div>
          <div style={{display:"flex",gap:10,flexShrink:0}}>
            <button onClick={()=>setPage("tasks")} style={{background:"rgba(255,255,255,0.12)",border:"1px solid rgba(255,255,255,0.2)",borderRadius:8,padding:"9px 18px",color:"#fff",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:font,transition:"background 0.15s"}}
              onMouseEnter={e=>e.currentTarget.style.background="rgba(255,255,255,0.2)"}
              onMouseLeave={e=>e.currentTarget.style.background="rgba(255,255,255,0.12)"}>
              View Tasks →
            </button>
          </div>
        </div>

        {/* ── KPI ROW — SimilarWeb style: clean numbers + sparklines ── */}
        <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:16,marginBottom:24}}>
          {[
            { label:"Total Locations",  value:14,        spark:[12,13,13,14,14,14], color:"#2563eb", change:"+1 this quarter" },
            { label:"High Risk",        value:highRisk,  spark:[1,2,3,2,3,highRisk], color:"#dc2626", change:`${highRisk} require action` },
            { label:"Open Tasks",       value:openTasks, spark:[8,10,12,9,11,openTasks], color:"#d97706", change:`${overdue} overdue` },
            { label:"Completion Rate",  value:`${pct}%`, spark:[65,70,72,75,80,pct], color:"#16a34a", change:"Last 6 months" },
          ].map(({label, value, spark, color, change}) => (
            <div key={label} style={{...cs, padding:"20px 22px", cursor:"default", transition:"box-shadow 0.2s"}}
              onMouseEnter={e=>e.currentTarget.style.boxShadow=dark?"0 4px 20px rgba(0,0,0,0.4)":"0 4px 20px rgba(0,0,0,0.1)"}
              onMouseLeave={e=>e.currentTarget.style.boxShadow=dark?"0 1px 8px rgba(0,0,0,0.3)":"0 1px 4px rgba(0,0,0,0.04)"}>
              <div style={{fontSize:11,color:D.text3,textTransform:"uppercase",letterSpacing:"0.8px",fontFamily:mono,marginBottom:12}}>{label}</div>
              <div style={{display:"flex",alignItems:"flex-end",justifyContent:"space-between",gap:8}}>
                <div style={{fontSize:38,fontWeight:800,color:D.text1,letterSpacing:"-1.5px",lineHeight:1}}>{value}</div>
                <Spark data={spark} color={color}/>
              </div>
              <div style={{fontSize:11,color:D.text3,marginTop:10}}>{change}</div>
            </div>
          ))}
        </div>

        {/* ── CHARTS ROW ── */}
        <div style={{display:"grid",gridTemplateColumns:"1.5fr 1fr",gap:16,marginBottom:24}}>

          {/* Risk by State */}
          <div style={{...cs, padding:"22px 24px"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
              <div>
                <div style={{fontSize:15,fontWeight:700,color:D.text1,letterSpacing:"-0.3px"}}>Risk by State</div>
                <div style={{fontSize:12,color:D.text3,marginTop:3}}>Composite risk score · 6 active states</div>
              </div>
              <span style={{fontSize:10,color:"#16a34a",fontWeight:700,fontFamily:mono,background:dark?"rgba(22,163,74,0.12)":"#f0fdf4",border:"1px solid #bbf7d0",borderRadius:5,padding:"3px 9px"}}>LIVE</span>
            </div>
            <ResponsiveContainer width="100%" height={200}>
              <BarChart data={RISK_BY_STATE} margin={{top:4,right:4,left:-28,bottom:0}} barCategoryGap="40%">
                <defs>
                  {RISK_BY_STATE.map((s,i)=>{
                    const c=s.score>=65?["#dc2626","#fca5a5"]:s.score>=50?["#d97706","#fcd34d"]:["#16a34a","#86efac"];
                    return <linearGradient key={i} id={`dg${i}`} x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={c[0]}/><stop offset="100%" stopColor={c[1]} stopOpacity={0.6}/></linearGradient>;
                  })}
                </defs>
                <CartesianGrid stroke={D.border} strokeDasharray="3 3" vertical={false} opacity={0.5}/>
                <XAxis dataKey="state" tick={{fill:D.text2,fontSize:12,fontWeight:600}} axisLine={false} tickLine={false}/>
                <YAxis tick={{fill:D.text3,fontSize:10}} axisLine={false} tickLine={false} domain={[0,100]}/>
                <Tooltip content={<CT/>} cursor={{fill:dark?"rgba(255,255,255,0.04)":"rgba(0,0,0,0.03)"}}/>
                <Bar dataKey="score" name="Risk Score" radius={[5,5,0,0]} maxBarSize={40}>
                  {RISK_BY_STATE.map((_,i)=><Cell key={i} fill={`url(#dg${i})`}/>)}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>

          {/* Completion Trend */}
          <div style={{...cs, padding:"22px 24px"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:20}}>
              <div>
                <div style={{fontSize:15,fontWeight:700,color:D.text1,letterSpacing:"-0.3px"}}>Completion Rate</div>
                <div style={{fontSize:12,color:D.text3,marginTop:3}}>6-month task close rate</div>
              </div>
              <div style={{fontSize:28,fontWeight:800,color:"#16a34a",letterSpacing:"-1px"}}>{pct}%</div>
            </div>
            <ResponsiveContainer width="100%" height={200}>
              <AreaChart data={COMPLETION_TREND} margin={{top:4,right:4,left:-28,bottom:0}}>
                <defs>
                  <linearGradient id="ag2" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%" stopColor="#16a34a" stopOpacity={dark?0.3:0.15}/>
                    <stop offset="100%" stopColor="#16a34a" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid stroke={D.border} strokeDasharray="3 3" vertical={false} opacity={0.5}/>
                <XAxis dataKey="month" tick={{fill:D.text2,fontSize:11}} axisLine={false} tickLine={false}/>
                <YAxis tick={{fill:D.text3,fontSize:10}} axisLine={false} tickLine={false} domain={[50,100]}/>
                <Tooltip content={<CT/>}/>
                <Area type="monotone" dataKey="rate" name="Rate %" stroke="#16a34a" strokeWidth={2.5} fill="url(#ag2)" dot={false} activeDot={{r:4,stroke:"#16a34a",strokeWidth:2,fill:D.card}}/>
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* ── BOTTOM GRID ── */}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:16}}>

          {/* Location Risk Table */}
          <div style={{...cs, padding:"22px 24px", gridColumn:"span 2"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:18}}>
              <div style={{fontSize:15,fontWeight:700,color:D.text1,letterSpacing:"-0.3px"}}>Location Risk Table</div>
              <button onClick={()=>setPage("locations")} style={{background:"none",border:`1px solid ${D.border}`,borderRadius:7,padding:"5px 12px",color:D.text2,fontSize:12,cursor:"pointer",fontFamily:font}}>View All →</button>
            </div>
            <table style={{width:"100%",borderCollapse:"collapse"}}>
              <thead>
                <tr style={{borderBottom:`1px solid ${D.border}`}}>
                  {["Location","State","Risk Score","Tasks","Status"].map(h=>(
                    <th key={h} style={{color:D.text3,fontWeight:600,textAlign:"left",padding:"8px 10px",fontSize:10,textTransform:"uppercase",letterSpacing:"0.7px",fontFamily:mono}}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {LOCATIONS.slice(0,6).map(l=>(
                  <tr key={l.id} style={{borderBottom:`1px solid ${D.border}`,transition:"background 0.12s",cursor:"pointer"}}
                    onMouseEnter={e=>e.currentTarget.style.background=D.cardAlt}
                    onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                    <td style={{padding:"12px 10px",color:D.text1,fontWeight:600,fontSize:13}}>{l.name}</td>
                    <td style={{padding:"12px 10px"}}><span style={{fontFamily:mono,fontSize:11,fontWeight:700,color:D.text2}}>{l.state}</span></td>
                    <td style={{padding:"12px 10px"}}>
                      <div style={{display:"flex",alignItems:"center",gap:8}}>
                        <div style={{width:56,height:4,background:D.border,borderRadius:2,overflow:"hidden"}}>
                          <div style={{width:`${l.risk}%`,height:"100%",background:l.risk>=65?"#ef4444":l.risk>=50?"#f59e0b":"#22c55e",borderRadius:2}}/>
                        </div>
                        <span style={{fontSize:12,fontWeight:700,color:l.risk>=65?"#dc2626":l.risk>=50?"#d97706":"#16a34a",fontFamily:mono}}>{l.risk}</span>
                      </div>
                    </td>
                    <td style={{padding:"12px 10px",color:l.tasks>2?D.amber:D.text2,fontWeight:700,fontFamily:mono,fontSize:13}}>{l.tasks}</td>
                    <td style={{padding:"12px 10px"}}><Badge variant={l.status}>{l.status}</Badge></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Right column — Overdue + Recent Regs */}
          <div style={{display:"flex",flexDirection:"column",gap:16}}>

            {/* Overdue */}
            <div style={{...cs, padding:"20px 22px", flex:1}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
                <div style={{fontSize:14,fontWeight:700,color:D.text1,letterSpacing:"-0.2px"}}>Overdue</div>
                <div style={{background:dark?"rgba(220,38,38,0.12)":"#fef2f2",border:"1px solid #fecaca",borderRadius:6,padding:"2px 8px",fontSize:11,fontWeight:700,color:"#dc2626",fontFamily:mono}}>{overdue}</div>
              </div>
              {TASKS_INIT.filter(t=>t.status==="overdue").slice(0,3).map(t=>(
                <div key={t.id} style={{padding:"10px 0",borderBottom:`1px solid ${D.border}`}}>
                  <div style={{fontSize:12,fontWeight:600,color:D.text1,marginBottom:3,lineHeight:1.35}}>{t.name}</div>
                  <div style={{fontSize:11,color:D.text3}}>{t.state} · Due {t.dueDate}</div>
                </div>
              ))}
            </div>

            {/* Recent Regulations */}
            <div style={{...cs, padding:"20px 22px", flex:1}}>
              <div style={{fontSize:14,fontWeight:700,color:D.text1,letterSpacing:"-0.2px",marginBottom:14}}>Recent Regulations</div>
              {REGULATIONS.slice(0,3).map(r=>{
                const c=r.severity==="high"?"#dc2626":r.severity==="medium"?"#d97706":"#16a34a";
                return (
                  <div key={r.id} style={{display:"flex",alignItems:"flex-start",gap:10,padding:"10px 0",borderBottom:`1px solid ${D.border}`}}>
                    <div style={{width:6,height:6,borderRadius:"50%",background:c,marginTop:5,flexShrink:0,boxShadow:`0 0 5px ${c}60`}}/>
                    <div>
                      <div style={{fontSize:12,fontWeight:600,color:D.text1,marginBottom:2,lineHeight:1.35}}>{r.title}</div>
                      <div style={{fontSize:11,color:D.text3}}>{r.state} · {r.date}</div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

      </div>
    </div>
  );
};
const LocationsPage = ({ onSelectLocation, currentUser }) => {
  const { dark, theme:th } = useTheme(); const D = th||LIGHT;
  const [search, setSearch] = useState("");
  const [filterState, setFilterState] = useState("All");
  const [filterStatus, setFilterStatus] = useState("All");
  const font = "'Plus Jakarta Sans',sans-serif";
  const cs = { background:D.card, border:`1px solid ${D.border}`, borderRadius:16, boxShadow:dark?"0 2px 16px rgba(0,0,0,0.4)":"0 2px 12px rgba(0,0,0,0.06)", overflow:"hidden" };

  const filtered = LOCATIONS.filter(l => {
    if (filterState !== "All" && l.state !== filterState) return false;
    if (filterStatus !== "All" && l.status !== filterStatus) return false;
    if (search && !l.name.toLowerCase().includes(search.toLowerCase()) && !l.city.toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });

  const kpis = [
    { label:"Total Facilities", value:LOCATIONS.length, icon:Building2, color:D.blue, bg:"rgba(37,99,235,0.1)", grad:"linear-gradient(135deg,#2563eb,#3b82f6)" },
    { label:"High Risk",        value:LOCATIONS.filter(l=>l.status==="high").length, icon:AlertTriangle, color:D.red, bg:"rgba(220,38,38,0.1)", grad:"linear-gradient(135deg,#dc2626,#ef4444)" },
    { label:"Dispensaries",     value:LOCATIONS.filter(l=>l.type==="Dispensary").length, icon:MapPin, color:D.green, bg:"rgba(22,163,74,0.1)", grad:"linear-gradient(135deg,#16a34a,#22c55e)" },
    { label:"Grow / Mfg",      value:LOCATIONS.filter(l=>l.type!=="Dispensary").length, icon:Zap, color:D.gold, bg:"rgba(180,83,9,0.1)", grad:"linear-gradient(135deg,#92400e,#d97706)" },
  ];

  return (
    <div style={{ background:D.bg, minHeight:"100vh", transition:"background 0.3s", paddingBottom:40 }}>
      <TopBar title="Locations" sub={`${LOCATIONS.length} facilities across ${COMPANY.states.length} states`}/>
      <div style={{ padding:"24px 28px 0" }}>
        {/* KPIs */}
        <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:14, marginBottom:20 }}>
          {kpis.map(({ label,value,icon:Icon,color,bg,grad }) => (
            <div key={label} style={{ ...cs, padding:0 }}>
              <div style={{ height:3, background:grad }}/>
              <div style={{ padding:"16px 18px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                <div>
                  <div style={{ fontSize:10, fontWeight:700, color:D.text3, textTransform:"uppercase", letterSpacing:"0.8px", fontFamily:"'Space Mono',monospace", marginBottom:8 }}>{label}</div>
                  <div style={{ fontSize:36, fontWeight:800, color:D.text1, fontFamily:font, letterSpacing:"-1.5px", lineHeight:1 }}>{value}</div>
                </div>
                <div style={{ width:42, height:42, borderRadius:12, background:bg, display:"flex", alignItems:"center", justifyContent:"center" }}>
                  <Icon size={20} color={color}/>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Filters */}
        <div style={{ ...cs, padding:"14px 18px", marginBottom:16, display:"flex", gap:12, alignItems:"center", flexWrap:"wrap" }}>
          <div style={{ display:"flex", alignItems:"center", gap:8, background:D.cardAlt, border:`1px solid ${D.border}`, borderRadius:8, padding:"7px 12px", flex:"0 0 220px" }}>
            <Search size={13} color={D.text3}/>
            <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search locations…" style={{ background:"none", border:"none", outline:"none", color:D.text1, fontSize:13, fontFamily:font, width:"100%" }}/>
          </div>
          <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
            {["All","OH","PA","VA","NV","IL","CA"].map(s => (
              <button key={s} onClick={()=>setFilterState(s)} style={{ background:filterState===s?D.green:"none", color:filterState===s?"#fff":D.text2, border:`1px solid ${filterState===s?D.green:D.border}`, borderRadius:7, padding:"5px 12px", fontSize:12, fontWeight:600, cursor:"pointer", fontFamily:font, transition:"all 0.15s" }}>{s}</button>
            ))}
          </div>
          <div style={{ display:"flex", gap:6 }}>
            {["All","high","medium","low"].map(s => (
              <button key={s} onClick={()=>setFilterStatus(s)} style={{ background:filterStatus===s?D.green:"none", color:filterStatus===s?"#fff":D.text2, border:`1px solid ${filterStatus===s?D.green:D.border}`, borderRadius:7, padding:"5px 12px", fontSize:12, fontWeight:600, cursor:"pointer", fontFamily:font, transition:"all 0.15s", textTransform:"capitalize" }}>{s}</button>
            ))}
          </div>
          <div style={{ marginLeft:"auto", fontSize:12, color:D.text3, fontFamily:font }}>{filtered.length} of {LOCATIONS.length} locations</div>
        </div>

        {/* Table */}
        <div style={cs}>
          <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
            <thead>
              <tr style={{ background:D.cardAlt }}>
                {["Location","State","City","Type","Manager","Risk","Tasks","Last Audit","Status"].map(h => (
                  <th key={h} style={{ color:D.text3, fontWeight:700, textAlign:"left", padding:"12px 16px", fontSize:10, textTransform:"uppercase", letterSpacing:"0.8px", fontFamily:"'Space Mono',monospace", borderBottom:`1px solid ${D.border}` }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map((l,i) => (
                <tr key={l.id} onClick={() => onSelectLocation(l.id)}
                  style={{ borderBottom:`1px solid ${D.border}`, cursor:"pointer", transition:"background 0.12s" }}
                  onMouseEnter={e=>e.currentTarget.style.background=D.cardAlt}
                  onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                  <td style={{ padding:"13px 16px", color:D.text1, fontWeight:700, fontSize:13 }}>{l.name}</td>
                  <td style={{ padding:"13px 16px" }}><span style={{ color:D.text2, fontFamily:"'Space Mono',monospace", fontSize:11, fontWeight:700 }}>{l.state}</span></td>
                  <td style={{ padding:"13px 16px", color:D.text2, fontSize:12 }}>{l.city}</td>
                  <td style={{ padding:"13px 16px" }}><Badge variant={l.type}>{l.type}</Badge></td>
                  <td style={{ padding:"13px 16px", color:D.text2, fontSize:12 }}>{l.manager}</td>
                  <td style={{ padding:"13px 16px" }}><RiskDot score={l.risk} size={38}/></td>
                  <td style={{ padding:"13px 16px", color:l.tasks>2?D.amber:D.text2, fontFamily:"'IBM Plex Mono',monospace", fontWeight:700, fontSize:13 }}>{l.tasks}</td>
                  <td style={{ padding:"13px 16px", color:D.text3, fontSize:11 }}>{l.lastAudit}</td>
                  <td style={{ padding:"13px 16px" }}><Badge variant={l.status}>{l.status}</Badge></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

/* ─────────────────────────────────────────────
   REGULATIONS PAGE
───────────────────────────────────────────── */
const RegulationsPage = ({ currentUser }) => {
  const { dark, theme:th } = useTheme(); const D = th||LIGHT;
  const [filterState, setFilterState] = useState("All");
  const [filterSev,   setFilterSev]   = useState("All");
  const [expanded, setExpanded] = useState(null);
  const font = "'Plus Jakarta Sans',sans-serif";
  const cs = { background:D.card, border:`1px solid ${D.border}`, borderRadius:16, boxShadow:dark?"0 2px 16px rgba(0,0,0,0.4)":"0 2px 12px rgba(0,0,0,0.06)" };

  const filtered = REGULATIONS.filter(r => {
    if (filterState !== "All" && r.state !== filterState) return false;
    if (filterSev !== "All" && r.severity !== filterSev) return false;
    return true;
  });

  const sevCounts = { high:REGULATIONS.filter(r=>r.severity==="high").length, medium:REGULATIONS.filter(r=>r.severity==="medium").length, low:REGULATIONS.filter(r=>r.severity==="low").length };

  return (
    <div style={{ background:D.bg, minHeight:"100vh", transition:"background 0.3s", paddingBottom:40 }}>
      <TopBar title="Regulation Updates" sub="State cannabis authority publications — auto-monitored"/>
      <div style={{ padding:"24px 28px 0" }}>

        {/* KPI row */}
        <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:14, marginBottom:20 }}>
          {[
            { label:"Total Updates",   value:REGULATIONS.length, icon:FileText, color:D.blue,  bg:"rgba(37,99,235,0.1)",  grad:"linear-gradient(135deg,#2563eb,#3b82f6)" },
            { label:"High Severity",   value:sevCounts.high,     icon:AlertTriangle, color:D.red,   bg:"rgba(220,38,38,0.1)",  grad:"linear-gradient(135deg,#dc2626,#ef4444)" },
            { label:"Medium Severity", value:sevCounts.medium,   icon:AlertCircle,   color:D.amber, bg:"rgba(217,119,6,0.1)",  grad:"linear-gradient(135deg,#b45309,#f59e0b)" },
            { label:"Low Severity",    value:sevCounts.low,      icon:Check,         color:D.green, bg:"rgba(22,163,74,0.1)",  grad:"linear-gradient(135deg,#16a34a,#22c55e)" },
          ].map(({ label,value,icon:Icon,color,bg,grad }) => (
            <div key={label} style={{ ...cs, padding:0, overflow:"hidden" }}>
              <div style={{ height:3, background:grad }}/>
              <div style={{ padding:"16px 18px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                <div>
                  <div style={{ fontSize:10, fontWeight:700, color:D.text3, textTransform:"uppercase", letterSpacing:"0.8px", fontFamily:"'Space Mono',monospace", marginBottom:8 }}>{label}</div>
                  <div style={{ fontSize:36, fontWeight:800, color:D.text1, fontFamily:font, letterSpacing:"-1.5px", lineHeight:1 }}>{value}</div>
                </div>
                <div style={{ width:42, height:42, borderRadius:12, background:bg, display:"flex", alignItems:"center", justifyContent:"center" }}>
                  <Icon size={20} color={color}/>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Filters */}
        <div style={{ ...cs, padding:"14px 18px", marginBottom:16, display:"flex", gap:10, alignItems:"center", flexWrap:"wrap" }}>
          <span style={{ fontSize:11, color:D.text3, fontFamily:"'Space Mono',monospace", fontWeight:700, textTransform:"uppercase", letterSpacing:"1px" }}>State:</span>
          {["All","OH","PA","VA","NV","IL","CA"].map(s => (
            <button key={s} onClick={()=>setFilterState(s)} style={{ background:filterState===s?D.green:"none", color:filterState===s?"#fff":D.text2, border:`1px solid ${filterState===s?D.green:D.border}`, borderRadius:7, padding:"5px 12px", fontSize:12, fontWeight:600, cursor:"pointer", fontFamily:font, transition:"all 0.15s" }}>{s}</button>
          ))}
          <div style={{ width:1, height:20, background:D.border }}/>
          <span style={{ fontSize:11, color:D.text3, fontFamily:"'Space Mono',monospace", fontWeight:700, textTransform:"uppercase", letterSpacing:"1px" }}>Severity:</span>
          {["All","high","medium","low"].map(s => (
            <button key={s} onClick={()=>setFilterSev(s)} style={{ background:filterSev===s?D.green:"none", color:filterSev===s?"#fff":D.text2, border:`1px solid ${filterSev===s?D.green:D.border}`, borderRadius:7, padding:"5px 12px", fontSize:12, fontWeight:600, cursor:"pointer", fontFamily:font, transition:"all 0.15s", textTransform:"capitalize" }}>{s}</button>
          ))}
        </div>

        {/* Regulation cards */}
        <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
          {filtered.map(r => {
            const impacted = LOCATIONS.filter(l => r.impacts.includes(l.id));
            const open = expanded === r.id;
            const sevColor = r.severity==="high"?D.red:r.severity==="medium"?D.amber:D.green;
            const sevBg = dark
              ? (r.severity==="high"?"rgba(220,38,38,0.08)":r.severity==="medium"?"rgba(217,119,6,0.08)":"rgba(22,163,74,0.08)")
              : (r.severity==="high"?"#fef2f2":r.severity==="medium"?"#fffbeb":"#f0fdf4");
            return (
              <div key={r.id} style={{ ...cs, overflow:"hidden" }}>
                <button onClick={() => setExpanded(open ? null : r.id)} style={{ width:"100%", display:"flex", alignItems:"center", gap:14, padding:"16px 20px", background:"none", border:"none", cursor:"pointer", textAlign:"left" }}>
                  <div style={{ width:4, alignSelf:"stretch", borderRadius:2, background:sevColor, flexShrink:0 }}/>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:5, flexWrap:"wrap" }}>
                      <span style={{ fontFamily:"'Space Mono',monospace", fontSize:11, fontWeight:800, color:sevColor, background:sevBg, padding:"2px 8px", borderRadius:5 }}>{r.state}</span>
                      <span style={{ fontSize:14, fontWeight:700, color:D.text1, fontFamily:font }}>{r.title}</span>
                    </div>
                    <div style={{ display:"flex", gap:12, alignItems:"center" }}>
                      <span style={{ fontSize:11, color:D.text3 }}>{r.date}</span>
                      <span style={{ fontSize:11, color:D.text3 }}>·</span>
                      <span style={{ fontSize:11, color:D.text3 }}>{impacted.length} location{impacted.length!==1?"s":""} impacted</span>
                      <Badge variant={r.severity}>{r.severity}</Badge>
                    </div>
                  </div>
                  <ChevronDown size={16} color={D.text3} style={{ transform:open?"rotate(180deg)":"none", transition:"transform .2s", flexShrink:0 }}/>
                </button>
                {open && (
                  <div style={{ padding:"0 20px 20px", borderTop:`1px solid ${D.border}` }}>
                    <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:32, marginTop:16, marginBottom:16 }}>
                      <div style={{ background:D.cardAlt, borderRadius:10, padding:"14px 16px" }}>
                        <div style={{ fontSize:10, color:D.text3, textTransform:"uppercase", letterSpacing:"1px", fontFamily:"'Space Mono',monospace", marginBottom:8, fontWeight:700 }}>Summary</div>
                        <p style={{ fontSize:13, color:D.text2, lineHeight:1.65, margin:0, fontFamily:font }}>{r.summary}</p>
                      </div>
                      <div style={{ background:dark?"rgba(217,119,6,0.08)":"#fffbeb", border:`1px solid ${D.amber}22`, borderRadius:10, padding:"14px 16px" }}>
                        <div style={{ fontSize:10, color:D.amber, textTransform:"uppercase", letterSpacing:"1px", fontFamily:"'Space Mono',monospace", marginBottom:8, fontWeight:700 }}>Required Action</div>
                        <p style={{ fontSize:13, color:D.text1, lineHeight:1.65, margin:0, fontFamily:font }}>{r.action}</p>
                      </div>
                    </div>
                    <div style={{ marginBottom:14 }}>
                      <div style={{ fontSize:10, color:D.text3, textTransform:"uppercase", letterSpacing:"1px", fontFamily:"'Space Mono',monospace", marginBottom:8, fontWeight:700 }}>Impacted Locations ({impacted.length})</div>
                      <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
                        {impacted.map(l => <span key={l.id} style={{ background:D.cardAlt, border:`1px solid ${D.border}`, borderRadius:7, padding:"4px 12px", fontSize:12, color:D.text1, fontFamily:font, fontWeight:600 }}>{l.name}</span>)}
                      </div>
                    </div>
                    <div style={{ display:"flex", gap:8 }}>
                      <button style={{ background:"linear-gradient(135deg,#16a34a,#22c55e)", border:"none", borderRadius:8, padding:"9px 18px", color:"#fff", fontSize:13, fontWeight:700, cursor:"pointer", fontFamily:font }}>Create Tasks</button>
                      <button style={{ background:"none", border:`1px solid ${D.border}`, borderRadius:8, padding:"9px 18px", color:D.text2, fontSize:13, fontWeight:600, cursor:"pointer", fontFamily:font }}>Mark Reviewed</button>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

/* ─────────────────────────────────────────────
   TASKS PAGE
───────────────────────────────────────────── */
const TasksPage = ({ currentUser }) => {
  const { dark, theme:th } = useTheme(); const D = th||LIGHT;
  const [tasks, setTasks] = useState(TASKS_INIT);
  const [filterStatus, setFilterStatus] = useState("All");
  const [filterState,  setFilterState]  = useState("All");
  const [search, setSearch] = useState("");
  const font = "'Plus Jakarta Sans',sans-serif";
  const cs = { background:D.card, border:`1px solid ${D.border}`, borderRadius:16, boxShadow:dark?"0 2px 16px rgba(0,0,0,0.4)":"0 2px 12px rgba(0,0,0,0.06)" };

  const markComplete = id => setTasks(ts => ts.map(t => t.id===id ? {...t, status:"completed", proof:true} : t));

  const filtered = tasks.filter(t => {
    if (filterStatus !== "All" && t.status !== filterStatus) return false;
    if (filterState  !== "All" && t.state  !== filterState)  return false;
    if (search && !t.name.toLowerCase().includes(search.toLowerCase()) && !t.location.toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });

  const counts = {
    overdue:     tasks.filter(t=>t.status==="overdue").length,
    "in-progress":tasks.filter(t=>t.status==="in-progress").length,
    open:        tasks.filter(t=>t.status==="open").length,
    completed:   tasks.filter(t=>t.status==="completed").length,
  };

  return (
    <div style={{ background:D.bg, minHeight:"100vh", transition:"background 0.3s", paddingBottom:40 }}>
      <TopBar title="Task Management" sub="Compliance remediation tasks across all locations"/>
      <div style={{ padding:"24px 28px 0" }}>

        {/* KPIs + CTA */}
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr 1fr auto", gap:14, marginBottom:20, alignItems:"start" }}>
          {[
            { label:"Overdue",     value:counts.overdue,          color:D.red,   bg:"rgba(220,38,38,0.1)",  grad:"linear-gradient(135deg,#dc2626,#ef4444)", icon:AlertCircle },
            { label:"In Progress", value:counts["in-progress"],   color:D.blue,  bg:"rgba(37,99,235,0.1)",  grad:"linear-gradient(135deg,#2563eb,#3b82f6)", icon:Clock },
            { label:"Open",        value:counts.open,             color:D.amber, bg:"rgba(217,119,6,0.1)",  grad:"linear-gradient(135deg,#b45309,#f59e0b)", icon:AlertTriangle },
            { label:"Completed",   value:counts.completed,        color:D.green, bg:"rgba(22,163,74,0.1)",  grad:"linear-gradient(135deg,#16a34a,#22c55e)", icon:Check },
          ].map(({ label,value,color,bg,grad,icon:Icon }) => (
            <div key={label} style={{ ...cs, padding:0, overflow:"hidden" }}>
              <div style={{ height:3, background:grad }}/>
              <div style={{ padding:"14px 16px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                <div>
                  <div style={{ fontSize:9, fontWeight:700, color:D.text3, textTransform:"uppercase", letterSpacing:"0.8px", fontFamily:"'Space Mono',monospace", marginBottom:6 }}>{label}</div>
                  <div style={{ fontSize:32, fontWeight:800, color:D.text1, fontFamily:font, letterSpacing:"-1.5px", lineHeight:1 }}>{value}</div>
                </div>
                <div style={{ width:36, height:36, borderRadius:10, background:bg, display:"flex", alignItems:"center", justifyContent:"center" }}>
                  <Icon size={17} color={color}/>
                </div>
              </div>
            </div>
          ))}
          <button style={{ background:"linear-gradient(135deg,#16a34a,#22c55e)", border:"none", borderRadius:12, padding:"0 20px", color:"#fff", fontSize:13, fontWeight:700, cursor:"pointer", fontFamily:font, display:"flex", alignItems:"center", gap:7, height:70, whiteSpace:"nowrap", boxShadow:"0 4px 14px rgba(22,163,74,0.3)" }}>
            <Plus size={16}/> New Task
          </button>
        </div>

        {/* Filters */}
        <div style={{ ...cs, padding:"14px 18px", marginBottom:16, display:"flex", gap:10, alignItems:"center", flexWrap:"wrap" }}>
          <div style={{ display:"flex", alignItems:"center", gap:8, background:D.cardAlt, border:`1px solid ${D.border}`, borderRadius:8, padding:"7px 12px" }}>
            <Search size={13} color={D.text3}/>
            <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search tasks…" style={{ background:"none", border:"none", outline:"none", color:D.text1, fontSize:13, fontFamily:font, width:170 }}/>
          </div>
          {["All","overdue","in-progress","open","completed"].map(s => (
            <button key={s} onClick={()=>setFilterStatus(s)} style={{ background:filterStatus===s?D.green:"none", color:filterStatus===s?"#fff":D.text2, border:`1px solid ${filterStatus===s?D.green:D.border}`, borderRadius:7, padding:"5px 12px", fontSize:12, fontWeight:600, cursor:"pointer", fontFamily:font, transition:"all 0.15s", textTransform:"capitalize", whiteSpace:"nowrap" }}>{s.replace("-"," ")}</button>
          ))}
          <div style={{ width:1, height:20, background:D.border }}/>
          {["All","OH","PA","VA","NV","IL","CA"].map(s => (
            <button key={s} onClick={()=>setFilterState(s)} style={{ background:filterState===s?D.green:"none", color:filterState===s?"#fff":D.text2, border:`1px solid ${filterState===s?D.green:D.border}`, borderRadius:7, padding:"5px 12px", fontSize:12, fontWeight:600, cursor:"pointer", fontFamily:font, transition:"all 0.15s" }}>{s}</button>
          ))}
        </div>

        {/* Table */}
        <div style={cs}>
          <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
            <thead>
              <tr style={{ background:D.cardAlt }}>
                {["Task","State","Location","Priority","Due Date","Owner","Status","Proof","Actions"].map(h => (
                  <th key={h} style={{ color:D.text3, fontWeight:700, textAlign:"left", padding:"12px 14px", fontSize:10, textTransform:"uppercase", letterSpacing:"0.8px", fontFamily:"'Space Mono',monospace", borderBottom:`1px solid ${D.border}` }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map(t => (
                <tr key={t.id} style={{ borderBottom:`1px solid ${D.border}`, transition:"background 0.12s" }}
                  onMouseEnter={e=>e.currentTarget.style.background=D.cardAlt}
                  onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                  <td style={{ padding:"12px 14px", maxWidth:220 }}>
                    <div style={{ fontWeight:700, color:D.text1, fontSize:13, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", fontFamily:font }}>{t.name}</div>
                  </td>
                  <td style={{ padding:"12px 14px" }}><span style={{ color:D.text2, fontFamily:"'Space Mono',monospace", fontSize:11, fontWeight:700 }}>{t.state}</span></td>
                  <td style={{ padding:"12px 14px", color:D.text2, fontSize:12, maxWidth:140 }}>
                    <div style={{ overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{t.location}</div>
                  </td>
                  <td style={{ padding:"12px 14px" }}><Badge variant={t.priority}>{t.priority}</Badge></td>
                  <td style={{ padding:"12px 14px", color:t.status==="overdue"?D.red:D.text2, fontSize:12, fontFamily:"'IBM Plex Mono',monospace", fontWeight:t.status==="overdue"?700:400 }}>{t.dueDate}</td>
                  <td style={{ padding:"12px 14px", color:D.text2, fontSize:12 }}>{t.owner}</td>
                  <td style={{ padding:"12px 14px" }}><Badge variant={t.status}>{t.status.replace("-"," ")}</Badge></td>
                  <td style={{ padding:"12px 14px" }}>
                    {t.proof
                      ? <span style={{ color:D.green, fontSize:12, fontWeight:700, display:"flex", alignItems:"center", gap:4 }}><Check size={12}/> Filed</span>
                      : <span style={{ color:D.text3, fontSize:12 }}>—</span>}
                  </td>
                  <td style={{ padding:"12px 14px" }}>
                    <div style={{ display:"flex", gap:6 }}>
                      {t.status !== "completed" && (
                        <button onClick={()=>markComplete(t.id)} style={{ background:`${D.green}18`, border:`1px solid ${D.green}30`, borderRadius:7, padding:"4px 10px", color:D.green, fontSize:11, cursor:"pointer", fontWeight:700, fontFamily:font }}>Done</button>
                      )}
                      <button style={{ background:D.cardAlt, border:`1px solid ${D.border}`, borderRadius:7, padding:"4px 10px", color:D.text2, fontSize:11, cursor:"pointer" }}>
                        <Upload size={11}/>
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

/* ─────────────────────────────────────────────
   EVIDENCE PAGE
───────────────────────────────────────────── */
const EvidencePage = ({ currentUser }) => {
  const { dark, theme:th } = useTheme(); const D = th||LIGHT;
  const [filterState, setFilterState] = useState("All");
  const [filterType,  setFilterType]  = useState("All");
  const font = "'Plus Jakarta Sans',sans-serif";
  const cs = { background:D.card, border:`1px solid ${D.border}`, borderRadius:16, boxShadow:dark?"0 2px 16px rgba(0,0,0,0.4)":"0 2px 12px rgba(0,0,0,0.06)" };

  const filtered = DOCUMENTS.filter(d => {
    if (filterState !== "All" && d.state !== filterState) return false;
    if (filterType  !== "All" && d.type  !== filterType)  return false;
    return true;
  });

  const types = ["All", ...new Set(DOCUMENTS.map(d=>d.type))];

  return (
    <div style={{ background:D.bg, minHeight:"100vh", transition:"background 0.3s", paddingBottom:40 }}>
      <TopBar title="Evidence & Documents" sub="Compliance proof uploads and audit trail"/>
      <div style={{ padding:"24px 28px 0" }}>

        {/* KPIs */}
        <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:14, marginBottom:20 }}>
          {[
            { label:"Total Documents", value:DOCUMENTS.length, icon:FileText, color:D.blue,  bg:"rgba(37,99,235,0.1)",  grad:"linear-gradient(135deg,#2563eb,#3b82f6)" },
            { label:"Verified",        value:DOCUMENTS.filter(d=>d.verified).length, icon:Check, color:D.green, bg:"rgba(22,163,74,0.1)", grad:"linear-gradient(135deg,#16a34a,#22c55e)" },
            { label:"Pending Review",  value:DOCUMENTS.filter(d=>!d.verified).length, icon:Clock, color:D.amber, bg:"rgba(217,119,6,0.1)", grad:"linear-gradient(135deg,#b45309,#f59e0b)" },
            { label:"Expiring Soon",   value:DOCUMENTS.filter(d=>d.expiring).length, icon:AlertTriangle, color:D.red, bg:"rgba(220,38,38,0.1)", grad:"linear-gradient(135deg,#dc2626,#ef4444)" },
          ].map(({ label,value,icon:Icon,color,bg,grad }) => (
            <div key={label} style={{ ...cs, padding:0, overflow:"hidden" }}>
              <div style={{ height:3, background:grad }}/>
              <div style={{ padding:"16px 18px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                <div>
                  <div style={{ fontSize:10, fontWeight:700, color:D.text3, textTransform:"uppercase", letterSpacing:"0.8px", fontFamily:"'Space Mono',monospace", marginBottom:8 }}>{label}</div>
                  <div style={{ fontSize:36, fontWeight:800, color:D.text1, fontFamily:font, letterSpacing:"-1.5px", lineHeight:1 }}>{value}</div>
                </div>
                <div style={{ width:42, height:42, borderRadius:12, background:bg, display:"flex", alignItems:"center", justifyContent:"center" }}>
                  <Icon size={20} color={color}/>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Filters + Upload */}
        <div style={{ ...cs, padding:"14px 18px", marginBottom:16, display:"flex", gap:10, alignItems:"center", flexWrap:"wrap" }}>
          {["All","OH","PA","VA","NV","IL","CA"].map(s => (
            <button key={s} onClick={()=>setFilterState(s)} style={{ background:filterState===s?D.green:"none", color:filterState===s?"#fff":D.text2, border:`1px solid ${filterState===s?D.green:D.border}`, borderRadius:7, padding:"5px 12px", fontSize:12, fontWeight:600, cursor:"pointer", fontFamily:font, transition:"all 0.15s" }}>{s}</button>
          ))}
          <div style={{ width:1, height:20, background:D.border }}/>
          {types.map(t => (
            <button key={t} onClick={()=>setFilterType(t)} style={{ background:filterType===t?D.green:"none", color:filterType===t?"#fff":D.text2, border:`1px solid ${filterType===t?D.green:D.border}`, borderRadius:7, padding:"5px 12px", fontSize:12, fontWeight:600, cursor:"pointer", fontFamily:font, transition:"all 0.15s" }}>{t}</button>
          ))}
          <button style={{ marginLeft:"auto", background:"linear-gradient(135deg,#16a34a,#22c55e)", border:"none", borderRadius:9, padding:"8px 18px", color:"#fff", fontSize:13, fontWeight:700, cursor:"pointer", fontFamily:font, display:"flex", alignItems:"center", gap:7, boxShadow:"0 4px 14px rgba(22,163,74,0.3)" }}>
            <Upload size={14}/> Upload Document
          </button>
        </div>

        {/* Document grid */}
        <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:14 }}>
          {filtered.map(d => (
            <div key={d.id} style={{ ...cs, padding:"20px 20px 16px", cursor:"pointer", transition:"transform 0.2s, box-shadow 0.2s" }}
              onMouseEnter={e=>{e.currentTarget.style.transform="translateY(-3px)";e.currentTarget.style.boxShadow="0 12px 36px rgba(0,0,0,0.12)";}}
              onMouseLeave={e=>{e.currentTarget.style.transform="none";e.currentTarget.style.boxShadow=dark?"0 2px 16px rgba(0,0,0,0.4)":"0 2px 12px rgba(0,0,0,0.06)";}}>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:12 }}>
                <div style={{ width:40, height:40, borderRadius:10, background:d.verified?"rgba(22,163,74,0.1)":"rgba(217,119,6,0.1)", display:"flex", alignItems:"center", justifyContent:"center" }}>
                  <FileText size={18} color={d.verified?D.green:D.amber}/>
                </div>
                <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", gap:4 }}>
                  <Badge variant={d.verified?"low":"medium"}>{d.verified?"Verified":"Pending"}</Badge>
                  {d.expiring && <span style={{ fontSize:9, color:D.red, fontWeight:700, fontFamily:"'Space Mono',monospace" }}>EXPIRING SOON</span>}
                </div>
              </div>
              <div style={{ fontSize:14, fontWeight:700, color:D.text1, marginBottom:4, lineHeight:1.3, fontFamily:font }}>{d.name}</div>
              <div style={{ fontSize:12, color:D.text3, marginBottom:10 }}>{d.location}</div>
              <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
                <span style={{ fontSize:10, fontWeight:700, color:D.text2, fontFamily:"'Space Mono',monospace", background:D.cardAlt, border:`1px solid ${D.border}`, borderRadius:5, padding:"2px 8px" }}>{d.state}</span>
                <span style={{ fontSize:10, color:D.text3, fontFamily:font, background:D.cardAlt, border:`1px solid ${D.border}`, borderRadius:5, padding:"2px 8px" }}>{d.type}</span>
                <span style={{ fontSize:10, color:D.text3, fontFamily:font, marginLeft:"auto" }}>{d.uploaded}</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

/* ─────────────────────────────────────────────
   REPORTING PAGE
───────────────────────────────────────────── */
const ReportingPage = ({ currentUser }) => {
  const { dark, theme:th } = useTheme(); const D = th||LIGHT;
  const font = "'Plus Jakarta Sans',sans-serif";
  const cs = { background:D.card, border:`1px solid ${D.border}`, borderRadius:16, boxShadow:dark?"0 2px 16px rgba(0,0,0,0.4)":"0 2px 12px rgba(0,0,0,0.06)" };

  const CT = ({ active, payload, label }) => {
    if (!active || !payload?.length) return null;
    return (
      <div style={{ background:D.card, border:`1px solid ${D.border}`, borderRadius:10, padding:"10px 14px", boxShadow:"0 8px 24px rgba(0,0,0,0.18)" }}>
        <p style={{ color:D.text3, fontSize:11, marginBottom:5, fontFamily:"monospace" }}>{label}</p>
        {payload.map((p,i) => <p key={i} style={{ color:p.color, fontSize:13, fontWeight:700, fontFamily:"monospace", margin:0 }}>{p.name}: {p.value}</p>)}
      </div>
    );
  };

  return (
    <div style={{ background:D.bg, minHeight:"100vh", transition:"background 0.3s", paddingBottom:40 }}>
      <TopBar title="Executive Reports" sub="Company-wide compliance analytics and board-ready summaries"/>
      <div style={{ padding:"24px 28px 0" }}>

        {/* Summary KPIs */}
        <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:14, marginBottom:20 }}>
          {[
            { label:"Overall Risk Score",   value:"61",   suffix:"", icon:Activity,   color:D.amber, bg:"rgba(217,119,6,0.1)",  grad:"linear-gradient(135deg,#b45309,#f59e0b)" },
            { label:"Task Completion Rate", value:"84",   suffix:"%",icon:CheckCircle2,color:D.green, bg:"rgba(22,163,74,0.1)",  grad:"linear-gradient(135deg,#16a34a,#22c55e)" },
            { label:"Open Regulations",     value:"8",    suffix:"", icon:Shield,     color:D.blue,  bg:"rgba(37,99,235,0.1)",  grad:"linear-gradient(135deg,#2563eb,#3b82f6)" },
            { label:"Audit Readiness",      value:"78",   suffix:"%",icon:Star,       color:D.gold,  bg:"rgba(180,83,9,0.1)",   grad:"linear-gradient(135deg,#92400e,#d97706)" },
          ].map(({ label,value,suffix,icon:Icon,color,bg,grad }) => (
            <div key={label} style={{ ...cs, padding:0, overflow:"hidden" }}>
              <div style={{ height:3, background:grad }}/>
              <div style={{ padding:"16px 18px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                <div>
                  <div style={{ fontSize:10, fontWeight:700, color:D.text3, textTransform:"uppercase", letterSpacing:"0.8px", fontFamily:"'Space Mono',monospace", marginBottom:8 }}>{label}</div>
                  <div style={{ fontSize:36, fontWeight:800, color:D.text1, fontFamily:font, letterSpacing:"-1.5px", lineHeight:1 }}>{value}<span style={{fontSize:20}}>{suffix}</span></div>
                </div>
                <div style={{ width:42, height:42, borderRadius:12, background:bg, display:"flex", alignItems:"center", justifyContent:"center" }}>
                  <Icon size={20} color={color}/>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Charts */}
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:14, marginBottom:14 }}>
          <div style={{ ...cs, padding:"22px 22px 16px" }}>
            <div style={{ fontSize:15, fontWeight:700, color:D.text1, fontFamily:font, marginBottom:4, letterSpacing:"-0.3px" }}>Completion Trend</div>
            <div style={{ fontSize:12, color:D.text3, marginBottom:16 }}>Monthly task close rate across all states</div>
            <ResponsiveContainer width="100%" height={200}>
              <AreaChart data={COMPLETION_TREND} margin={{top:4,right:4,left:-24,bottom:0}}>
                <defs>
                  <linearGradient id="rg2" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%" stopColor={D.green} stopOpacity={dark?0.4:0.2}/>
                    <stop offset="100%" stopColor={D.green} stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid stroke={D.border} strokeDasharray="4 4" vertical={false} opacity={0.5}/>
                <XAxis dataKey="month" tick={{fill:D.text2,fontSize:11}} axisLine={false} tickLine={false}/>
                <YAxis tick={{fill:D.text3,fontSize:10}} axisLine={false} tickLine={false} domain={[50,100]}/>
                <Tooltip content={<CT/>}/>
                <Area type="monotone" dataKey="rate" name="Rate %" stroke={D.green} strokeWidth={2.5} fill="url(#rg2)" dot={false} activeDot={{r:5,stroke:D.green,strokeWidth:2,fill:D.card}}/>
              </AreaChart>
            </ResponsiveContainer>
          </div>
          <div style={{ ...cs, padding:"22px 22px 16px" }}>
            <div style={{ fontSize:15, fontWeight:700, color:D.text1, fontFamily:font, marginBottom:4, letterSpacing:"-0.3px" }}>Risk by State</div>
            <div style={{ fontSize:12, color:D.text3, marginBottom:16 }}>Current composite risk score per state</div>
            <ResponsiveContainer width="100%" height={200}>
              <BarChart data={RISK_BY_STATE} margin={{top:4,right:4,left:-24,bottom:0}} barCategoryGap="32%">
                <defs>
                  {RISK_BY_STATE.map((s,i)=>{
                    const c=s.score>=65?["#dc2626","#f87171"]:s.score>=50?["#b45309","#fbbf24"]:["#15803d","#4ade80"];
                    return <linearGradient key={i} id={`rp${i}`} x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={c[0]}/><stop offset="100%" stopColor={c[1]} stopOpacity={0.7}/></linearGradient>;
                  })}
                </defs>
                <CartesianGrid stroke={D.border} strokeDasharray="4 4" vertical={false} opacity={0.5}/>
                <XAxis dataKey="state" tick={{fill:D.text2,fontSize:12,fontWeight:700}} axisLine={false} tickLine={false}/>
                <YAxis tick={{fill:D.text3,fontSize:10}} axisLine={false} tickLine={false} domain={[0,100]}/>
                <Tooltip content={<CT/>}/>
                <Bar dataKey="score" name="Risk" radius={[7,7,0,0]}>
                  {RISK_BY_STATE.map((_,i)=><Cell key={i} fill={`url(#rp${i})`}/>)}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Audit Readiness Table */}
        <div style={{ ...cs, padding:"22px 22px 18px" }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
            <div>
              <div style={{ fontSize:15, fontWeight:700, color:D.text1, fontFamily:font, letterSpacing:"-0.3px" }}>Audit Readiness by Location</div>
              <div style={{ fontSize:12, color:D.text3, marginTop:2 }}>Inspection-ready score based on open tasks, proof filings, and document status</div>
            </div>
            <button style={{ background:"linear-gradient(135deg,#16a34a,#22c55e)", border:"none", borderRadius:9, padding:"9px 18px", color:"#fff", fontSize:13, fontWeight:700, cursor:"pointer", fontFamily:font, display:"flex", alignItems:"center", gap:7 }}>
              <FileText size={14}/> Export PDF
            </button>
          </div>
          <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
            <thead>
              <tr style={{ background:D.cardAlt }}>
                {["Location","State","Audit Score","Open Tasks","Documents","Status"].map(h => (
                  <th key={h} style={{ color:D.text3, fontWeight:700, textAlign:"left", padding:"11px 14px", fontSize:10, textTransform:"uppercase", letterSpacing:"0.8px", fontFamily:"'Space Mono',monospace", borderBottom:`1px solid ${D.border}` }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {AUDIT_READINESS.map(a => {
                const color = a.score>=80?D.green:a.score>=60?D.amber:D.red;
                return (
                  <tr key={a.location} style={{ borderBottom:`1px solid ${D.border}`, transition:"background 0.12s" }}
                    onMouseEnter={e=>e.currentTarget.style.background=D.cardAlt}
                    onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                    <td style={{ padding:"12px 14px", color:D.text1, fontWeight:700, fontFamily:font }}>{a.location}</td>
                    <td style={{ padding:"12px 14px" }}><span style={{ fontFamily:"'Space Mono',monospace", fontSize:11, fontWeight:700, color:D.text2 }}>{a.state}</span></td>
                    <td style={{ padding:"12px 14px" }}>
                      <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                        <div style={{ flex:1, height:6, background:D.border, borderRadius:3, overflow:"hidden", maxWidth:100 }}>
                          <div style={{ width:`${a.score}%`, height:"100%", background:`linear-gradient(90deg,${color}88,${color})`, borderRadius:3 }}/>
                        </div>
                        <span style={{ fontSize:13, fontWeight:800, color, fontFamily:font, minWidth:32 }}>{a.score}%</span>
                      </div>
                    </td>
                    <td style={{ padding:"12px 14px", color:a.openTasks>2?D.amber:D.text2, fontWeight:700, fontFamily:"'IBM Plex Mono',monospace" }}>{a.openTasks}</td>
                    <td style={{ padding:"12px 14px", color:D.text2, fontSize:12 }}>{a.documents} filed</td>
                    <td style={{ padding:"12px 14px" }}><Badge variant={a.score>=80?"low":a.score>=60?"medium":"high"}>{a.score>=80?"Ready":a.score>=60?"In Progress":"At Risk"}</Badge></td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

