const CHAT_STYLES = `
  @keyframes sproutSway    { 0%,100%{transform:rotate(-2deg) translateY(0px)} 50%{transform:rotate(1deg) translateY(-3px)} }
  @keyframes dotBounce     { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-5px)} }
  @keyframes revealFadeIn  { from{opacity:0} to{opacity:1} }
  @keyframes revealScaleUp { from{opacity:0;transform:scale(0.93) translateY(12px)} to{opacity:1;transform:scale(1) translateY(0)} }
  @keyframes notifBounce   { 0%{transform:scale(0)} 60%{transform:scale(1.25)} 100%{transform:scale(1)} }
  @keyframes handWave {
    0%   { transform: rotate(0deg)   scale(1);    }
    15%  { transform: rotate(-10deg) scale(1.04); }
    35%  { transform: rotate(8deg)   scale(1.02); }
    55%  { transform: rotate(-6deg)  scale(1);    }
    75%  { transform: rotate(4deg)   scale(1);    }
    100% { transform: rotate(0deg)   scale(1);    }
  }
  @keyframes handBounce {
    0%,100% { transform: translateY(0px)  scale(1);    }
    50%     { transform: translateY(-5px) scale(1.08); }
  }
`;

const CP_SYSTEM_PROMPT = `You are CompliancePilot's client services AI — a precise, authoritative compliance intelligence assistant for cannabis multi-state operators.

Tone: Concise, expert, professional. Like a senior compliance counsel who respects the reader's time. No filler phrases, no casual language, no first-person name. Direct answers only.

CompliancePilot platform:
- Multi-state cannabis compliance management for operators in OH, PA, VA, NV, IL, CA
- Real-time regulation monitoring, task routing, evidence filing, audit readiness scoring
- Role-based access: Executive, Compliance Officer, Location Manager, Platform Admin
- Pricing: Enterprise contracts only, custom per operator. Minimum 3 locations.
- SOC 2 Type II, 256-bit encryption, role-based access controls
- Implementation: 2-3 weeks average. Dedicated onboarding specialist assigned.

Never refer to yourself by name. Never use phrases like "Great question!" or "Happy to help!". Be direct and informative. Keep responses under 4 sentences unless detail is specifically requested.`;

const QUICK_CHIPS = [
  { label:"State coverage",    msg:"What states do you currently cover?" },
  { label:"Risk scoring",      msg:"How does the risk scoring system work?" },
  { label:"Pricing & plans",   msg:"How is pricing structured?" },
  { label:"Implementation",    msg:"What does the implementation process look like?" },
  { label:"Book a specialist", msg:"I'd like to speak with a compliance specialist." },
];

const SproutMascot = ({ state = "idle", size = 52 }) => {
  const waveAnim = state === "thinking"
    ? "handBounce 1s ease-in-out infinite"
    : "handWave 2.6s ease-in-out infinite";
  return (
    <div style={{ width:size, height:size, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, fontSize:size*0.72, lineHeight:1, animation:waveAnim, transformOrigin:"bottom center", userSelect:"none" }}>
      👋
    </div>
  );
};

const ChatBot = ({ font }) => {
  const f = font || "'Plus Jakarta Sans',sans-serif";
  const [open,      setOpen]      = useState(false);
  const [messages,  setMessages]  = useState([]);
  const [input,     setInput]     = useState("");
  const [loading,   setLoading]   = useState(false);
  const [showChips, setShowChips] = useState(true);
  const [notif,     setNotif]     = useState(false);
  const [leadStep,  setLeadStep]  = useState(null);
  const [leadData,  setLeadData]  = useState({});
  const bottomRef = useRef(null);

  const GREETING = { role:"assistant", content:"Good day. I'm CompliancePilot's compliance intelligence assistant.\n\nI can answer questions about our platform, multi-state coverage, implementation timelines, and pricing — or connect you directly with a specialist.\n\nHow can I assist you?" };

  useEffect(() => {
    const t = setTimeout(() => { setMessages([GREETING]); setNotif(true); }, 2500);
    return () => clearTimeout(t);
  }, []);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior:"smooth" });
  }, [messages, loading]);

  const sendMessage = async (text) => {
    const userText = (text || input).trim();
    if (!userText || loading) return;
    setInput(""); setShowChips(false); setNotif(false);

    if (leadStep !== null) {
      if (leadStep === 0) {
        setLeadData(d => ({ ...d, name:userText }));
        setMessages(m => [...m, { role:"user", content:userText }, { role:"assistant", content:`Thank you, ${userText}. What is your work email so our team can follow up?` }]);
        setLeadStep(1); return;
      }
      if (leadStep === 1) {
        setLeadData(d => ({ ...d, email:userText }));
        setMessages(m => [...m, { role:"user", content:userText }, { role:"assistant", content:"Which states does your operation cover?" }]);
        setLeadStep(2); return;
      }
      if (leadStep === 2) {
        setLeadData(d => ({ ...d, states:userText }));
        setMessages(m => [...m, { role:"user", content:userText }, { role:"assistant", content:`Noted. Our team will be in touch shortly.\n\n**Summary:**\n• States: ${userText}\n• Contact: ${leadData.email}` }]);
        setLeadStep(null); return;
      }
    }

    const demoWords = ["demo","book","schedule","pricing","cost","how much","price","specialist"];
    const wantsDemo = demoWords.some(w => userText.toLowerCase().includes(w));
    const shouldCaptureLead = wantsDemo && leadStep === null && leadData.email === undefined;
    const history = [...messages, { role:"user", content:userText }];
    setMessages(history);
    setLoading(true);
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method:"POST",
        headers:{ "Content-Type":"application/json" },
        body: JSON.stringify({
          model:"claude-sonnet-4-20250514",
          max_tokens:500,
          system:CP_SYSTEM_PROMPT,
          messages:history.map(m => ({ role:m.role, content:m.content })),
        }),
      });
      const data = await res.json();
      const reply = data?.content?.map(b => b.text||"").join("") || "Apologies — please try again.";
      setMessages(h => [...h, { role:"assistant", content:reply }]);
      if (shouldCaptureLead) {
        setTimeout(() => {
          setMessages(h => [...h, { role:"assistant", content:"To connect you with the right specialist — may I have your name?" }]);
          setLeadStep(0);
        }, 800);
      }
    } catch {
      setMessages(h => [...h, { role:"assistant", content:"Connection error. Please try again." }]);
    }
    setLoading(false);
  };

  const renderMessage = (content) =>
    content.split("\n").map((line, i) => {
      if (!line.trim()) return <div key={i} style={{ height:4 }}/>;
      const parts = line.split(/\*\*(.*?)\*\*/g);
      return (
        <p key={i} style={{ margin:0, marginBottom:2, lineHeight:1.65, fontSize:13 }}>
          {parts.map((p, j) => j%2===1 ? <strong key={j}>{p}</strong> : p)}
        </p>
      );
    });

  const mascotState = loading ? "thinking" : "idle";

  return (
    <>
      <style>{CHAT_STYLES}</style>
      <div style={{ position:"fixed", bottom:24, right:24, zIndex:9999, display:"flex", flexDirection:"column", alignItems:"flex-end", gap:12 }}>

        {!open && (
          <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", gap:8 }}>
            <div style={{ background:"#fff", borderRadius:"12px 12px 3px 12px", padding:"8px 14px", whiteSpace:"nowrap", boxShadow:"0 4px 16px rgba(0,0,0,0.12)", fontSize:13, fontWeight:600, color:"#0f172a", fontFamily:f, border:"1px solid #e2e8f0", animation:"revealScaleUp 0.3s cubic-bezier(.22,1,.36,1) both", animationDelay:"1.8s", opacity:0, animationFillMode:"forwards" }}>
              Need help?
            </div>
            <button onClick={() => setOpen(true)} style={{ width:58, height:58, borderRadius:"50%", border:"none", cursor:"pointer", background:"linear-gradient(135deg,#16a34a,#22c55e)", boxShadow:"0 4px 20px rgba(22,163,74,0.5)", display:"flex", alignItems:"center", justifyContent:"center", position:"relative", transition:"transform 0.2s, box-shadow 0.2s" }}
              onMouseEnter={e=>{e.currentTarget.style.transform="scale(1.08)";e.currentTarget.style.boxShadow="0 6px 28px rgba(22,163,74,0.65)";}}
              onMouseLeave={e=>{e.currentTarget.style.transform="scale(1)";e.currentTarget.style.boxShadow="0 4px 20px rgba(22,163,74,0.5)";}}>
              <SproutMascot state="idle" size={46}/>
              {notif && <div style={{ position:"absolute", top:0, right:0, width:14, height:14, borderRadius:"50%", background:"#f87171", border:"2px solid #fff", animation:"notifBounce 0.4s ease both" }}/>}
            </button>
          </div>
        )}

        {open && (
          <div style={{ width:360, borderRadius:20, overflow:"hidden", background:"#ffffff", border:"1px solid #e2e8f0", boxShadow:"0 20px 60px rgba(0,0,0,0.15)", display:"flex", flexDirection:"column", animation:"revealScaleUp 0.3s cubic-bezier(.22,1,.36,1) both" }}>

            <div style={{ background:"linear-gradient(135deg,#0b1f3a,#162d50)", padding:"6px 12px", borderBottom:"1px solid rgba(255,255,255,0.08)", display:"flex", alignItems:"center", gap:10, flexShrink:0 }}>
              <LogoImg size={64}/>
              <div style={{ flex:1 }}>
                <div style={{ fontSize:14, fontWeight:700, color:"#fff", fontFamily:f }}>CompliancePilot</div>
                <div style={{ display:"flex", alignItems:"center", gap:5, marginTop:2 }}>
                  <div style={{ width:6, height:6, borderRadius:"50%", background:"#4ade80", boxShadow:"0 0 5px rgba(74,222,128,0.6)" }}/>
                  <span style={{ fontSize:11, color:"rgba(255,255,255,0.45)", fontFamily:"'Space Mono',monospace" }}>Compliance Intelligence · Online</span>
                </div>
              </div>
              <div style={{ display:"flex", gap:5 }}>
                <button onClick={() => { setMessages([GREETING]); setShowChips(true); setLeadStep(null); setLeadData({}); }}
                  style={{ background:"rgba(255,255,255,0.07)", border:"1px solid rgba(255,255,255,0.1)", borderRadius:7, width:32, height:32, cursor:"pointer", color:"rgba(255,255,255,0.6)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:17, transition:"all 0.15s" }}
                  onMouseEnter={e=>{e.currentTarget.style.background="rgba(255,255,255,0.14)";e.currentTarget.style.color="#fff";}}
                  onMouseLeave={e=>{e.currentTarget.style.background="rgba(255,255,255,0.07)";e.currentTarget.style.color="rgba(255,255,255,0.6)";}}>
                  ↺
                </button>
                <button onClick={() => setOpen(false)} style={{ background:"rgba(255,255,255,0.07)", border:"1px solid rgba(255,255,255,0.1)", borderRadius:7, width:32, height:32, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", transition:"all 0.15s" }}
                  onMouseEnter={e=>e.currentTarget.style.background="rgba(255,255,255,0.14)"}
                  onMouseLeave={e=>e.currentTarget.style.background="rgba(255,255,255,0.07)"}>
                  <X size={14} color="rgba(255,255,255,0.6)"/>
                </button>
              </div>
            </div>

            <div style={{ height:360, overflowY:"auto", padding:"14px 12px 8px", display:"flex", flexDirection:"column", gap:10, scrollbarWidth:"thin", scrollbarColor:"#e2e8f0 transparent", background:"#ffffff" }}>
              {messages.map((m, i) => (
                <div key={i} style={{ display:"flex", justifyContent:m.role==="user"?"flex-end":"flex-start", gap:8, alignItems:"flex-end", animation:"revealFadeIn 0.2s ease both" }}>
                  <div style={{ maxWidth:"78%", padding:"9px 12px", borderRadius: m.role==="user" ? "14px 14px 3px 14px" : "14px 14px 14px 3px", background: m.role==="user" ? "linear-gradient(135deg,#16a34a,#22c55e)" : "#f1f5f9", border: m.role==="user" ? "none" : "1px solid #e2e8f0", color: m.role==="user" ? "#fff" : "#0f172a", fontFamily:f }}>
                    {renderMessage(m.content)}
                  </div>
                </div>
              ))}
              {loading && (
                <div style={{ display:"flex", alignItems:"flex-end", gap:8 }}>
                  <div style={{ background:"#f1f5f9", border:"1px solid #e2e8f0", borderRadius:"14px 14px 14px 3px", padding:"10px 14px", display:"flex", gap:5 }}>
                    {[0,1,2].map(i=>(
                      <div key={i} style={{ width:6, height:6, borderRadius:"50%", background:"#94a3b8", animation:"dotBounce 1.1s ease-in-out infinite", animationDelay:`${i*180}ms` }}/>
                    ))}
                  </div>
                </div>
              )}
              {showChips && messages.length <= 1 && !loading && (
                <div style={{ display:"flex", flexWrap:"wrap", gap:6, marginTop:4 }}>
                  {QUICK_CHIPS.map(c => (
                    <button key={c.label} onClick={() => sendMessage(c.msg)} style={{ background:"#f0fdf4", border:"1px solid #bbf7d0", borderRadius:20, padding:"5px 11px", color:"#15803d", fontSize:11, cursor:"pointer", fontFamily:f, transition:"all 0.15s" }}
                      onMouseEnter={e=>{e.currentTarget.style.background="#dcfce7";}}
                      onMouseLeave={e=>{e.currentTarget.style.background="#f0fdf4";}}>
                      {c.label}
                    </button>
                  ))}
                </div>
              )}
              <div ref={bottomRef}/>
            </div>

            <div style={{ padding:"10px 12px 14px", borderTop:"1px solid #e2e8f0", background:"#f8fafc", flexShrink:0 }}>
              <div style={{ display:"flex", gap:8, alignItems:"center" }}>
                <input value={input} onChange={e => setInput(e.target.value)}
                  onKeyDown={e => { if(e.key==="Enter"){e.preventDefault();sendMessage();} }}
                  placeholder="Ask about compliance, coverage, pricing…"
                  style={{ flex:1, background:"#ffffff", border:"1px solid #e2e8f0", borderRadius:10, padding:"9px 12px", color:"#0f172a", fontSize:13, fontFamily:f, outline:"none", transition:"border-color 0.15s" }}
                  onFocus={e=>e.target.style.borderColor="#16a34a"}
                  onBlur={e=>e.target.style.borderColor="#e2e8f0"}
                />
                <button onClick={()=>sendMessage()} disabled={!input.trim()||loading} style={{ width:36, height:36, borderRadius:9, border:"none", cursor:"pointer", flexShrink:0, background:input.trim()&&!loading ? "linear-gradient(135deg,#16a34a,#22c55e)" : "#e2e8f0", display:"flex", alignItems:"center", justifyContent:"center", transition:"all 0.2s" }}>
                  <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                    <path d="M13 1L6 8M13 1L9 13L6 8M13 1L1 5L6 8" stroke={input.trim()&&!loading?"#fff":"#94a3b8"} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </>
  );
};

