/* Auth Context via simple prop drilling */
const UserContext = React.createContext(null);

const RoleBadge = ({ role, font }) => {
  const map = {
    executive:  { bg:"#eff6ff", color:"#1d4ed8", label:"Executive" },
    compliance: { bg:"#f0fdf4", color:"#16a34a", label:"Compliance Officer" },
    manager:    { bg:"#ecfeff", color:"#0891b2", label:"Location Manager" },
    admin:      { bg:"#fffbeb", color:"#b45309", label:"Admin" },
  };
  const s = map[role] || map.compliance;
  return (
    <span style={{ fontSize:10, fontWeight:700, padding:"2px 8px", borderRadius:4,
      background:s.bg, color:s.color, fontFamily:font||"'IBM Plex Mono',monospace",
      letterSpacing:"0.3px", textTransform:"uppercase" }}>
      {s.label}
    </span>
  );
};

export default function App() {
  const [page,              setPage]              = useState("landing");
  const [selectedLocationId,setSelectedLocationId]= useState(null);
  const [currentUser,       setCurrentUser]       = useState(null);
  const [loginError,        setLoginError]        = useState("");

  const navigate = (p, locId = null) => {
    setPage(p);
    if (locId !== null) setSelectedLocationId(locId);
    window.scrollTo(0, 0);
  };

  /* ── AUTH FUNCTIONS ── */
  const signIn = (email, password) => {
    const user = MOCK_USERS.find(
      u => u.email.toLowerCase() === email.toLowerCase().trim() && u.password === password
    );
    if (user) {
      setCurrentUser(user);
      setLoginError("");
      // Route based on role
      navigate("dashboard");
      return true;
    } else {
      setLoginError("Incorrect email or password. Please try again.");
      return false;
    }
  };

  const signOut = () => {
    setCurrentUser(null);
    navigate("landing");
  };

  const signUp = (name, email, company, password) => {
    // In production this would create a real account
    // For now create a temp session as compliance officer role
    const newUser = {
      id:99, email, password, name,
      initials: name.split(" ").map(n=>n[0]).join("").slice(0,2).toUpperCase(),
      role:"compliance", roleLabel:"Compliance Officer",
      company, stateAccess:"all", locationAccess:"all",
      avatar:"#16a34a",
      permissions:{ dashboard:true, locations:true, regulations:true, tasks:true, evidence:true, reporting:true, admin:false },
    };
    setCurrentUser(newUser);
    setLoginError("");
    navigate("dashboard");
    return true;
  };

  const FONT_IMPORT = `
    @import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:ital,wght@0,300;0,400;0,500;0,600;0,700;0,800;1,700;1,800&family=Cormorant+Garamond:ital,wght@0,400;0,600;0,700;1,400;1,600;1,700&family=Space+Mono:wght@400;700&family=IBM+Plex+Mono:wght@400;500;600&display=swap');
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    ::-webkit-scrollbar { width: 5px; height: 5px; }
    ::-webkit-scrollbar-track { background: ${T.bg}; }
    ::-webkit-scrollbar-thumb { background: ${T.border}; border-radius: 3px; }
    button { font-family: 'Plus Jakarta Sans', sans-serif; }
    input, textarea, select { font-family: 'Plus Jakarta Sans', sans-serif; }
  `;

  /* ── LANDING ── */
  if (page === "landing") {
    return (
      <UserContext.Provider value={{ currentUser, signIn, signOut, signUp, loginError, setLoginError }}>
        <style>{FONT_IMPORT}</style>
        <LandingPage onLogin={() => navigate("dashboard")}/>
        <ChatBot font="'Plus Jakarta Sans',sans-serif"/>
      </UserContext.Provider>
    );
  }

  /* ── OLD LOGIN PAGE (legacy fallback) ── */

  /* ── PROTECTED DASHBOARD ── */
  if (!currentUser) {
    // Not logged in — bounce back to landing
    return (
      <UserContext.Provider value={{ currentUser, signIn, signOut, signUp, loginError, setLoginError }}>
        <style>{FONT_IMPORT}</style>
        <LandingPage onLogin={() => navigate("dashboard")}/>
        <ChatBot font="'Plus Jakarta Sans',sans-serif"/>
      </UserContext.Provider>
    );
  }

  return (
    <UserContext.Provider value={{ currentUser, signIn, signOut, signUp, loginError, setLoginError }}>
      <style>{FONT_IMPORT}</style>
      <AppLayout page={page} setPage={navigate} currentUser={currentUser} onSignOut={signOut}>
        {page === "dashboard"       && <DashboardPage setPage={navigate} currentUser={currentUser}/>}
        {page === "locations"       && <LocationsPage onSelectLocation={(id) => navigate("location-detail", id)} currentUser={currentUser}/>}
        {page === "location-detail" && <LocationDetailPage locationId={selectedLocationId} setPage={navigate} currentUser={currentUser}/>}
        {page === "regulations"     && <RegulationsPage currentUser={currentUser}/>}
        {page === "tasks"           && <TasksPage currentUser={currentUser}/>}
        {page === "evidence"        && <EvidencePage currentUser={currentUser}/>}
        {page === "reporting"       && (currentUser.permissions.reporting ? <ReportingPage currentUser={currentUser}/> : <AccessDenied/>)}
        {page === "admin"           && (currentUser.permissions.admin    ? <AdminPage currentUser={currentUser}/> : <AccessDenied/>)}
      </AppLayout>
    </UserContext.Provider>
  );
}
